[DataContractAttribute]
class ETGPurchAgreementHeaderAPIContract
{
    private VendAccount vendAccount;
    private EffectiveDate effectiveDate;
    private ExpirationDate expirationDate;
    private PaymTermId paymentTerms;
    private VendPaymMode methodOfPayment;
    private DlvModeId deliveryMode;
    private DlvTermId deliveryTerms;
    private CurrencyCode currencyCode;
    private VendInvoiceAccount invoiceAccount;
    private ETGPlaceOfLoading placeOfLoading;
    private ETGPlaceOfDischarge placeOfDischarge;
    private str businessUnit, costCenter;
    private str dealNumber;

}

